def _percentile(values: List[float], p: float) -> float:
    if not values:
        return 0.0
    values = sorted(values)
    if p <= 0:
        return float(values[0])
    if p >= 100:
        return float(values[-1])
    k = (len(values) - 1) * (p / 100.0)
    f = int(k)
    c = min(f + 1, len(values) - 1)
    if f == c:
        return float(values[int(k)])
    return float(values[f] * (c - k) + values[c] * (k - f))


def _http_get_json(base_url: str, path: str, query: Dict[str, Any]) -> Tuple[int, Any, float]:
    """Return (status_code, parsed_json_or_none, elapsed_ms)."""
    q = {k: query[k] for k in query if query[k] is not None}
    pairs = [(k, str(v)) for k, v in q.items()]
    qs = urllib.parse.urlencode(pairs)
    url = base_url.rstrip("/") + path
    if qs:
        url += "?" + qs
    req = urllib.request.Request(url, headers={"Accept": "application/json"})

    t0 = time.perf_counter()
    try:
        with urllib.request.urlopen(req, timeout=600) as resp:
            body = resp.read().decode("utf-8")
            status = resp.getcode() or 200
    except urllib.error.URLError as e:
        elapsed_ms = (time.perf_counter() - t0) * 1000.0
        reason = getattr(e, "reason", None)
        if isinstance(reason, OSError):
            return 0, {"error": str(reason), "errno": getattr(reason, "errno", None)}, elapsed_ms
        return 0, {"error": str(e)}, elapsed_ms
    except urllib.error.HTTPError as e:
        elapsed_ms = (time.perf_counter() - t0) * 1000.0
        try:
            body = e.read().decode("utf-8")
        except Exception:
            body = ""
        try:
            parsed = json.loads(body) if body else None
        except json.JSONDecodeError:
            parsed = None
        return e.code, parsed if parsed is not None else body, elapsed_ms
    elapsed_ms = (time.perf_counter() - t0) * 1000.0
    try:
        return status, json.loads(body), elapsed_ms
    except json.JSONDecodeError:
        return status, None, elapsed_ms


def _validate_listings(body: Any, exp: Dict[str, Any]) -> Tuple[bool, str, Dict[str, Any]]:
    if not isinstance(body, list):
        return False, "body is not a JSON array", {}
    li = exp["listings"]
    want_len = li["response_length"]
    if len(body) != want_len:
        return False, f"length {len(body)} != expected {want_len}", {"got_len": len(body), "want_len": want_len}

    for row in body:
        if not isinstance(row, dict):
            return False, "row is not an object", {}
        if "title" in row or "description" in row:
            return False, "summary must not include title/description", {}
        for key in ("id", "rooms", "area_sqm", "price", "listing_type", "tags", "lat", "lon", "floor"):
            if key not in row:
                return False, f"missing key {key!r}", {}

    got_ids = [str(x["id"]) for x in body]

    if "ordered_ids" in li:
        want = [str(x) for x in li["ordered_ids"]]
        if got_ids != want:
            return False, "ordered_ids mismatch", {"want_sample": want[:3], "got_sample": got_ids[:3]}
        return True, "", {"total_matching": li.get("total_matching")}

    if "ordered_ids_prefix" in li:
        pref = [str(x) for x in li["ordered_ids_prefix"]]
        n = int(li.get("compare_ordered_ids_prefix_length", len(pref)))
        n = min(n, len(pref), len(got_ids))
        if got_ids[:n] != pref[:n]:
            return False, f"ordered id prefix mismatch (first {n})", {}
        return True, "", {"total_matching": li.get("total_matching"), "prefix_compared": n}

    return False, "golden listings block must include ordered_ids or ordered_ids_prefix", {}


def _validate_clusters(body: Any, exp: Dict[str, Any]) -> Tuple[bool, str, Dict[str, Any]]:
    if not isinstance(body, list):
        return False, "body is not a JSON array", {}
    cl = exp["clusters"]
    max_c = int(cl["max_clusters"])
    if len(body) > max_c:
        return False, f"too many clusters: {len(body)} > {max_c}", {}

    bbox = cl["bbox"]
    oracle = int(cl["oracle_listing_count"])
    total = 0
    for c in body:
        if not isinstance(c, dict):
            return False, "cluster is not an object", {}
        for key in ("lat", "lon", "count"):
            if key not in c:
                return False, f"cluster missing {key!r}", {}
        if int(c["count"]) < 1:
            return False, "count < 1", {}
        total += int(c["count"])
        la, lo = float(c["lat"]), float(c["lon"])
        if not (bbox["min_lat"] <= la <= bbox["max_lat"] and bbox["min_lon"] <= lo <= bbox["max_lon"]):
            return False, "cluster coordinates outside bbox", {}

    details: Dict[str, Any] = {
        "oracle_listing_count": oracle,
        "sum_cluster_counts": total,
        "num_clusters": len(body),
    }

    mode = cl.get("mode", "relaxed")
    if mode == "strict":
        if total != oracle:
            return False, f"strict: sum(count) {total} != oracle {oracle}", details
        return True, "", details

    tol_rel = float(cl.get("sum_tolerance_rel", 0.05))
    tol_abs = float(cl.get("sum_tolerance_abs", 10_000))
    min_ratio = float(cl.get("min_sum_ratio", 0.0))

    if oracle == 0:
        if total != 0:
            return False, f"oracle 0 but sum was {total}", details
        return True, "", details

    err = abs(total - oracle)
    rel_ok = err / oracle <= tol_rel
    abs_ok = err <= tol_abs
    ratio_ok = total >= oracle * min_ratio if min_ratio > 0 else True

    if not ratio_ok:
        return False, f"sum ratio too low: {total}/{oracle}", details
    if not (rel_ok or abs_ok):
        return (
            False,
            f"sum {total} not within tolerance of oracle {oracle}",
            details,
        )
    details["relaxed_ok"] = True
    return True, "", details


def _run_case(
    base_url: str,
    case: Dict[str, Any],
    repeat: int,
) -> Dict[str, Any]:
    req = case["request"]
    path = req["path"]
    query = req.get("query") or {}
    exp = case["expected"]
    want_status = int(exp["status"])

    latencies: List[float] = []
    last_err = ""
    ok = True
    details: Dict[str, Any] = {}

    for i in range(repeat):
        status, body, ms = _http_get_json(base_url, path, query)
        latencies.append(ms)

        if status != want_status:
            ok = False
            details = {"http_status": status}
            if status == 0 and isinstance(body, dict):
                reason = body.get("error", "request failed")
                last_err = f"Request failed: {reason}"
                if "errno" in body:
                    details["errno"] = body["errno"]
            else:
                last_err = f"HTTP {status}, expected {want_status}"
            break

        if "listings" in exp:
            sub_ok, err, det = _validate_listings(body, exp)
            details = det
            if not sub_ok:
                ok = False
                last_err = err
                break
        elif "clusters" in exp:
            sub_ok, err, det = _validate_clusters(body, exp)
            details = det
            if not sub_ok:
                ok = False
                last_err = err
                break
        else:
            ok = False
            last_err = "golden case missing listings or clusters block"
            break

    mean_ms = sum(latencies) / len(latencies) if latencies else 0.0
    p95_ms = _percentile(latencies, 95.0) if latencies else 0.0

    return {
        "id": case["id"],
        "ok": ok,
        "error": last_err if not ok else None,
        "latencies_ms": latencies,
        "mean_ms": mean_ms,
        "p95_ms": p95_ms,
        "details": details,
    }


def main() -> None:
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--base-url", default="http://127.0.0.1:8080", help="API root URL.")
    ap.add_argument(
        "--repeat",
        "--calls",
        dest="repeat",
        type=int,
        default=1,
        help="Number of API calls per case before computing mean/p95 runtime statistics.",
    )
    ap.add_argument("--report-json", type=str, default=None)
    ap.add_argument("--report-csv", type=str, default=None)
    args = ap.parse_args()
    if args.repeat < 1:
        raise SystemExit("--repeat/--calls must be >= 1")

    all_results: List[Dict[str, Any]] = []
    base = args.base_url.rstrip("/")

    try:
        status, _, _ = _http_get_json(base, "/listings/health", {})
        if status == 0:
            raise SystemExit(
                "Cannot reach API at "
                f"{base}. Start the service first (for this project: ./mvnw spring-boot:run), "
                "or pass --base-url with the correct host/port."
            )
    except urllib.error.URLError as e:
        reason = getattr(e, "reason", None)
        if isinstance(reason, (ConnectionRefusedError, socket.timeout, OSError)):
            raise SystemExit(
                "Cannot reach API at "
                f"{base}. Start the service first (for this project: ./mvnw spring-boot:run), "
                "or pass --base-url with the correct host/port."
            )
        raise

    for data in EMBEDDED_SUITES:
        suite_name = data.get("suite", "embedded_suite")
        cases = data.get("cases", [])
        print(f"=== Suite: {suite_name} (embedded) ===")
        for case in cases:
            row = _run_case(base, case, args.repeat)
            row["suite"] = suite_name
            row["golden_file"] = "embedded"
            all_results.append(row)
            st = "OK" if row["ok"] else "FAIL"
            err = f" — {row['error']}" if row["error"] else ""
            print(
                f"  [{st}] {row['id']}  mean={row['mean_ms']:.2f}ms p95={row['p95_ms']:.2f}ms{err}"
            )

    if args.report_json:
        report_json_path = args.report_json
        report_json_parent = Path(report_json_path).expanduser().resolve().parent
        report_json_parent.mkdir(parents=True, exist_ok=True)
        Path(report_json_path).write_text(json.dumps({"results": all_results}, indent=2), encoding="utf-8")
    if args.report_csv:
        report_csv_path = args.report_csv
        report_csv_parent = Path(report_csv_path).expanduser().resolve().parent
        report_csv_parent.mkdir(parents=True, exist_ok=True)
        with open(report_csv_path, "w", newline="", encoding="utf-8") as f:
            w = csv.writer(f)
            w.writerow(["suite", "id", "ok", "mean_ms", "p95_ms", "error"])
            for r in all_results:
                w.writerow(
                    [
                        r.get("suite", ""),
                        r["id"],
                        r["ok"],
                        f"{r['mean_ms']:.3f}",
                        f"{r['p95_ms']:.3f}",
                        r.get("error") or "",
                    ]
                )

    if any(not r["ok"] for r in all_results):
        raise SystemExit(1)


if __name__ == "__main__":
    main()
